import{_ as i,o as s,c as e,ai as a}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"ClawHub","description":"","frontmatter":{"read_when":["向新用户介绍 ClawHub","安装、搜索或发布 Skills","说明 ClawHub CLI 标志和同步行为"],"summary":"ClawHub 指南：公共 Skills 注册中心 + CLI 工作流","title":"ClawHub","x-i18n":{"generated_at":"2026-02-01T21:42:32Z","model":"claude-opus-4-5","provider":"pi","source_hash":"8b7f8fab80a34e409f37fa130a49ff5b487966755a7b0d214dfebf5207c7124c","source_path":"tools/clawhub.md","workflow":15}},"headers":[],"relativePath":"zh-CN/tools/clawhub.md","filePath":"zh-CN/tools/clawhub.md","lastUpdated":1771906665000}'),d={name:"zh-CN/tools/clawhub.md"};function t(o,l,c,n,h,p){return s(),e("div",null,[...l[0]||(l[0]=[a('<h1 id="clawhub" tabindex="-1"><a class="header-anchor" href="#clawhub">#</a> ClawHub</h1><p>ClawHub 是 <strong>OpenSoul 的公共 Skills 注册中心</strong>。它是一项免费服务：所有 Skills 都是公开的、开放的，所有人都可以查看、共享和复用。Skills 就是一个包含 <code>SKILL.md</code> 文件（以及辅助文本文件）的文件夹。你可以在网页应用中浏览 Skills，也可以使用 CLI 来搜索、安装、更新和发布 Skills。</p><p>网站：<a href="https://clawhub.com" target="_blank" rel="noreferrer">clawhub.com</a></p><h2 id="适用人群-新手友好" tabindex="-1"><a class="header-anchor" href="#适用人群-新手友好">#</a> 适用人群（新手友好）</h2><p>如果你想为 OpenSoul 智能体添加新功能，ClawHub 是查找和安装 Skills 的最简单方式。你不需要了解后端的工作原理。你可以：</p><ul><li>使用自然语言搜索 Skills。</li><li>将 Skills 安装到你的工作区。</li><li>之后使用一条命令更新 Skills。</li><li>通过发布 Skills 来备份你自己的 Skills。</li></ul><h2 id="快速入门-非技术人员" tabindex="-1"><a class="header-anchor" href="#快速入门-非技术人员">#</a> 快速入门（非技术人员）</h2><ol><li>安装 CLI（参见下一节）。</li><li>搜索你需要的内容： <ul><li><code>clawhub search &quot;calendar&quot;</code></li></ul></li><li>安装一个 Skills： <ul><li><code>clawhub install &lt;skill-slug&gt;</code></li></ul></li><li>启动一个新的 OpenSoul 会话，以加载新 Skills。</li></ol><h2 id="安装-cli" tabindex="-1"><a class="header-anchor" href="#安装-cli">#</a> 安装 CLI</h2><p>任选其一：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clawhub</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clawhub</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="在-opensoul-中的定位" tabindex="-1"><a class="header-anchor" href="#在-opensoul-中的定位">#</a> 在 OpenSoul 中的定位</h2><p>默认情况下，CLI 会将 Skills 安装到当前工作目录下的 <code>./skills</code>。如果已配置 OpenSoul 工作区，<code>clawhub</code> 会回退到该工作区，除非你通过 <code>--workdir</code>（或 <code>CLAWHUB_WORKDIR</code>）进行覆盖。OpenSoul 从 <code>&lt;workspace&gt;/skills</code> 加载工作区 Skills，并会在<strong>下一个</strong>会话中生效。如果你已经在使用 <code>~/.opensoul/skills</code> 或内置 Skills，工作区 Skills 优先级更高。</p><p>有关 Skills 加载、共享和权限控制的更多详情，请参阅 <a href="/docs/tools/skills">Skills</a>。</p><h2 id="服务功能" tabindex="-1"><a class="header-anchor" href="#服务功能">#</a> 服务功能</h2><ul><li><strong>公开浏览</strong>Skills 及其 <code>SKILL.md</code> 内容。</li><li>基于嵌入向量（向量搜索）的<strong>搜索</strong>，而不仅仅是关键词匹配。</li><li>支持语义化版本号、变更日志和标签（包括 <code>latest</code>）的<strong>版本管理</strong>。</li><li>每个版本以 zip 格式<strong>下载</strong>。</li><li><strong>星标和评论</strong>，支持社区反馈。</li><li><strong>审核</strong>钩子，用于审批和审计。</li><li><strong>CLI 友好的 API</strong>，支持自动化和脚本编写。</li></ul><h2 id="cli-命令和参数" tabindex="-1"><a class="header-anchor" href="#cli-命令和参数">#</a> CLI 命令和参数</h2><p>全局选项（适用于所有命令）：</p><ul><li><code>--workdir &lt;dir&gt;</code>：工作目录（默认：当前目录；回退到 OpenSoul 工作区）。</li><li><code>--dir &lt;dir&gt;</code>：Skills 目录，相对于工作目录（默认：<code>skills</code>）。</li><li><code>--site &lt;url&gt;</code>：网站基础 URL（浏览器登录）。</li><li><code>--registry &lt;url&gt;</code>：注册中心 API 基础 URL。</li><li><code>--no-input</code>：禁用提示（非交互模式）。</li><li><code>-V, --cli-version</code>：打印 CLI 版本。</li></ul><p>认证：</p><ul><li><code>clawhub login</code>（浏览器流程）或 <code>clawhub login --token &lt;token&gt;</code></li><li><code>clawhub logout</code></li><li><code>clawhub whoami</code></li></ul><p>选项：</p><ul><li><code>--token &lt;token&gt;</code>：粘贴 API 令牌。</li><li><code>--label &lt;label&gt;</code>：为浏览器登录令牌存储的标签（默认：<code>CLI token</code>）。</li><li><code>--no-browser</code>：不打开浏览器（需要 <code>--token</code>）。</li></ul><p>搜索：</p><ul><li><code>clawhub search &quot;query&quot;</code></li><li><code>--limit &lt;n&gt;</code>：最大结果数。</li></ul><p>安装：</p><ul><li><code>clawhub install &lt;slug&gt;</code></li><li><code>--version &lt;version&gt;</code>：安装指定版本。</li><li><code>--force</code>：如果文件夹已存在则覆盖。</li></ul><p>更新：</p><ul><li><code>clawhub update &lt;slug&gt;</code></li><li><code>clawhub update --all</code></li><li><code>--version &lt;version&gt;</code>：更新到指定版本（仅限单个 slug）。</li><li><code>--force</code>：当本地文件与任何已发布版本不匹配时强制覆盖。</li></ul><p>列表：</p><ul><li><code>clawhub list</code>（读取 <code>.clawhub/lock.json</code>）</li></ul><p>发布：</p><ul><li><code>clawhub publish &lt;path&gt;</code></li><li><code>--slug &lt;slug&gt;</code>：Skills 标识符。</li><li><code>--name &lt;name&gt;</code>：显示名称。</li><li><code>--version &lt;version&gt;</code>：语义化版本号。</li><li><code>--changelog &lt;text&gt;</code>：变更日志文本（可以为空）。</li><li><code>--tags &lt;tags&gt;</code>：逗号分隔的标签（默认：<code>latest</code>）。</li></ul><p>删除/恢复（仅所有者/管理员）：</p><ul><li><code>clawhub delete &lt;slug&gt; --yes</code></li><li><code>clawhub undelete &lt;slug&gt; --yes</code></li></ul><p>同步（扫描本地 Skills + 发布新增/更新的 Skills）：</p><ul><li><code>clawhub sync</code></li><li><code>--root &lt;dir...&gt;</code>：额外的扫描根目录。</li><li><code>--all</code>：无提示上传所有内容。</li><li><code>--dry-run</code>：显示将要上传的内容。</li><li><code>--bump &lt;type&gt;</code>：更新的版本号递增类型 <code>patch|minor|major</code>（默认：<code>patch</code>）。</li><li><code>--changelog &lt;text&gt;</code>：非交互更新的变更日志。</li><li><code>--tags &lt;tags&gt;</code>：逗号分隔的标签（默认：<code>latest</code>）。</li><li><code>--concurrency &lt;n&gt;</code>：注册中心检查并发数（默认：4）。</li></ul><h2 id="智能体常用工作流" tabindex="-1"><a class="header-anchor" href="#智能体常用工作流">#</a> 智能体常用工作流</h2><h3 id="搜索-skills" tabindex="-1"><a class="header-anchor" href="#搜索-skills">#</a> 搜索 Skills</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;postgres backups&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="下载新-skills" tabindex="-1"><a class="header-anchor" href="#下载新-skills">#</a> 下载新 Skills</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-skill-pack</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="更新已安装的-skills" tabindex="-1"><a class="header-anchor" href="#更新已安装的-skills">#</a> 更新已安装的 Skills</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="备份你的-skills-发布或同步" tabindex="-1"><a class="header-anchor" href="#备份你的-skills-发布或同步">#</a> 备份你的 Skills（发布或同步）</h3><p>对于单个 Skills 文件夹：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> publish</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./my-skill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --slug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-skill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;My Skill&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.0.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tags</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>一次扫描并备份多个 Skills：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="高级详情-技术性" tabindex="-1"><a class="header-anchor" href="#高级详情-技术性">#</a> 高级详情（技术性）</h2><h3 id="版本管理和标签" tabindex="-1"><a class="header-anchor" href="#版本管理和标签">#</a> 版本管理和标签</h3><ul><li>每次发布都会创建一个新的<strong>语义化版本</strong> <code>SkillVersion</code>。</li><li>标签（如 <code>latest</code>）指向某个版本；移动标签可以实现回滚。</li><li>变更日志附加在每个版本上，在同步或发布更新时可以为空。</li></ul><h3 id="本地更改与注册中心版本" tabindex="-1"><a class="header-anchor" href="#本地更改与注册中心版本">#</a> 本地更改与注册中心版本</h3><p>更新时会使用内容哈希将本地 Skills 内容与注册中心版本进行比较。如果本地文件与任何已发布版本不匹配，CLI 会在覆盖前询问确认（或在非交互模式下需要 <code>--force</code>）。</p><h3 id="同步扫描和回退根目录" tabindex="-1"><a class="header-anchor" href="#同步扫描和回退根目录">#</a> 同步扫描和回退根目录</h3><p><code>clawhub sync</code> 首先扫描当前工作目录。如果未找到 Skills，它会回退到已知的旧版位置（例如 <code>~/opensoul/skills</code> 和 <code>~/.opensoul/skills</code>）。这样设计是为了在不需要额外标志的情况下找到旧版 Skills 安装。</p><h3 id="存储和锁文件" tabindex="-1"><a class="header-anchor" href="#存储和锁文件">#</a> 存储和锁文件</h3><ul><li>已安装的 Skills 记录在工作目录下的 <code>.clawhub/lock.json</code> 中。</li><li>认证令牌存储在 ClawHub CLI 配置文件中（可通过 <code>CLAWHUB_CONFIG_PATH</code> 覆盖）。</li></ul><h3 id="遥测-安装计数" tabindex="-1"><a class="header-anchor" href="#遥测-安装计数">#</a> 遥测（安装计数）</h3><p>当你在登录状态下运行 <code>clawhub sync</code> 时，CLI 会发送一个最小快照用于计算安装次数。你可以完全禁用此功能：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAWHUB_DISABLE_TELEMETRY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="环境变量" tabindex="-1"><a class="header-anchor" href="#环境变量">#</a> 环境变量</h2><ul><li><code>CLAWHUB_SITE</code>：覆盖网站 URL。</li><li><code>CLAWHUB_REGISTRY</code>：覆盖注册中心 API URL。</li><li><code>CLAWHUB_CONFIG_PATH</code>：覆盖 CLI 存储令牌/配置的位置。</li><li><code>CLAWHUB_WORKDIR</code>：覆盖默认工作目录。</li><li><code>CLAWHUB_DISABLE_TELEMETRY=1</code>：禁用 <code>sync</code> 的遥测功能。</li></ul>',64)])])}const k=i(d,[["render",t]]);export{u as __pageData,k as default};
